$(document).ready(function () {

    var baseUrl = window.location.origin;
    let retrive_data = baseUrl + '/ca_report_sales_ajax';

    let grandTotal = 0; // store total

    var table = $('#ca-report-sales').DataTable({
        processing: true,
        serverSide: true,
        destroy: true,
        dom: 'Bfrtip',

        buttons: [
            // ✅ EXCEL EXPORT
            {
                extend: 'excelHtml5',
                text: 'Export to Excel',
                filename: 'Seva_Pooja_Report',

                customize: function (xlsx) {
                    var sheet = xlsx.xl.worksheets['sheet1.xml'];

                    // Title
                    $('c[r=A1] t', sheet).text('Seva Pooja Report');

                    // Last row
                    var lastRow = $('row', sheet).length + 1;

                    // Grand total row
                    var grandTotalRow =
                        `<row r="${lastRow}">
                            <c t="inlineStr" r="A${lastRow}">
                                <is><t>Grand Total</t></is>
                            </c>
                            <c t="n" r="C${lastRow}">
                                <v>${parseFloat(grandTotal).toFixed(2)}</v>
                            </c>
                        </row>`;

                    sheet.childNodes[0].childNodes[1].innerHTML += grandTotalRow;
                }
            },

            // ✅ PDF EXPORT
            {
                extend: 'pdf',
                text: 'Export to PDF',
                filename: 'Seva_Pooja_Report',

                customize: function (doc) {

                    // Title
                    doc.content.splice(0, 0, {
                        text: 'Seva Pooja Report',
                        fontSize: 14,
                        bold: true,
                        margin: [0, 0, 0, 10]
                    });

                    // Grand total
                    doc.content.push({
                        text: 'Grand Total: ₹ ' + grandTotal,
                        margin: [0, 10, 0, 0],
                        bold: true
                    });
                }
            }
        ],

        ajax: {
            url: retrive_data,
            data: function (d) {
                d.from_date = $('.from_date').val();
                d.to_date = $('.to_date').val();
                d.financial_year = $('.financial_year').val();
                d.category = $('.category').val();
                d.subcategory = $('.subcategory').val();
            },
            dataSrc: function (json) {
                grandTotal = json.grand_total; // ✅ store total
                return json.data;
            }
        },

        columns: [
            {
                data: null,
                render: function (data, type, row, meta) {
                    return meta.row + 1;
                }
            },
            { data: "subcategory_name" },
            {
                data: "total_amount",
                render: function (data) {
                    return "₹ " + data;
                }
            }
        ]
    });

    // Reload on filter
    $('.submit_purchase_report').click(function () {
        table.ajax.reload();
    });

});